import{_ as i,C as d,o,c as s,E as r,w as a,a as n,a0 as l}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"United Kingdom Healthcare","description":"Healthcare and HRT access for transgender people in the United Kingdom","frontmatter":{"layout":"doc","title":"United Kingdom Healthcare","description":"Healthcare and HRT access for transgender people in the United Kingdom"},"headers":[],"relativePath":"europe/united-kingdom/healthcare.md","filePath":"europe/united-kingdom/healthcare.md","lastUpdated":null}'),h={name:"europe/united-kingdom/healthcare.md"};function c(g,t,p,u,m,b){const e=d("Badge");return o(),s("div",null,[r(e,{variant:"red"},{default:a(()=>[...t[0]||(t[0]=[n("Gatekeeping Model",-1)])]),_:1}),r(e,{variant:"yellow"},{default:a(()=>[...t[1]||(t[1]=[n("Private Options Available",-1)])]),_:1}),t[2]||(t[2]=l('<h1 id="healthcare-in-the-united-kingdom" tabindex="-1">Healthcare in the United Kingdom <a class="header-anchor" href="#healthcare-in-the-united-kingdom" aria-label="Permalink to &quot;Healthcare in the United Kingdom&quot;">​</a></h1><h2 id="gender-affirming-healthcare" tabindex="-1">Gender Affirming Healthcare <a class="header-anchor" href="#gender-affirming-healthcare" aria-label="Permalink to &quot;Gender Affirming Healthcare&quot;">​</a></h2><p>The UK operates a <strong>gatekeeping model</strong> through the National Health Service (NHS). Gender Identity Clinics (GICs) require a diagnosis of gender dysphoria before treatment. <strong>Waiting times are among the longest in Europe</strong> — 2-5 years for a first appointment at most NHS GICs.</p><h2 id="nhs-gender-identity-clinics" tabindex="-1">NHS Gender Identity Clinics <a class="header-anchor" href="#nhs-gender-identity-clinics" aria-label="Permalink to &quot;NHS Gender Identity Clinics&quot;">​</a></h2><h3 id="england" tabindex="-1">England <a class="header-anchor" href="#england" aria-label="Permalink to &quot;England&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Wait Time (First Appointment)</th></tr></thead><tbody><tr><td>The Gender Identity Clinic (GIC)</td><td>London (Tavistock)</td><td>4-5 years</td></tr><tr><td>Nottingham GIC</td><td>Nottingham</td><td>3-4 years</td></tr><tr><td>Exeter GIC</td><td>Exeter</td><td>3-4 years</td></tr><tr><td>Leeds GIC</td><td>Leeds</td><td>3-4 years</td></tr><tr><td>Sheffield GIC</td><td>Sheffield</td><td>3-4 years</td></tr><tr><td>Daventry GIC</td><td>Daventry</td><td>2-3 years</td></tr><tr><td>The Laurels</td><td>Exeter</td><td>3-4 years</td></tr><tr><td>Indigo (Manchester)</td><td>Manchester</td><td>2-3 years</td></tr></tbody></table><h3 id="scotland" tabindex="-1">Scotland <a class="header-anchor" href="#scotland" aria-label="Permalink to &quot;Scotland&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Wait Time</th></tr></thead><tbody><tr><td>Sandyford GIC</td><td>Glasgow</td><td>2-3 years</td></tr><tr><td>Chalmers GIC</td><td>Edinburgh</td><td>2-3 years</td></tr><tr><td>Grampian GIC</td><td>Aberdeen</td><td>1-2 years</td></tr><tr><td>Tayside GIC</td><td>Dundee</td><td>1-2 years</td></tr></tbody></table><h3 id="wales-and-northern-ireland" tabindex="-1">Wales and Northern Ireland <a class="header-anchor" href="#wales-and-northern-ireland" aria-label="Permalink to &quot;Wales and Northern Ireland&quot;">​</a></h3><ul><li><strong>Wales</strong>: Cardiff Gender Identity Clinic — 2-3 years</li><li><strong>Northern Ireland</strong>: Brackenburn Clinic, Belfast — 3-4 years</li></ul><h2 id="nhs-process" tabindex="-1">NHS Process <a class="header-anchor" href="#nhs-process" aria-label="Permalink to &quot;NHS Process&quot;">​</a></h2><ol><li>GP referral to a Gender Identity Clinic</li><li><strong>First appointment</strong>: 2-5 year wait. Initial assessment with a psychiatrist/psychologist</li><li><strong>Diagnosis</strong>: Gender dysphoria diagnosis after several appointments (typically 3-6 months)</li><li><strong>Hormone referral</strong>: Referred to endocrinology</li><li><strong>HRT</strong>: Endocrinology appointment — typically 3-6 months after diagnosis</li><li><strong>Follow-up</strong>: Regular monitoring, typically every 6-12 months</li></ol><h2 id="private-options" tabindex="-1">Private Options <a class="header-anchor" href="#private-options" aria-label="Permalink to &quot;Private Options&quot;">​</a></h2><p>Due to long NHS waits, many trans people in the UK use private healthcare:</p><table tabindex="0"><thead><tr><th>Provider</th><th>Services</th><th>Cost</th><th>Wait Time</th></tr></thead><tbody><tr><td><strong>GenderGP</strong></td><td>Online-only, informed consent model</td><td>£30/month subscription + £150 setup</td><td>2-4 weeks</td></tr><tr><td><strong>Gendercare</strong></td><td>London-based, psychiatrist + endocrinologist</td><td>£300-500 per appointment</td><td>3-6 months</td></tr><tr><td><strong>Gender Doctors</strong></td><td>Online + London</td><td>£300-500 per appointment</td><td>1-3 months</td></tr><tr><td><strong>YourGP</strong></td><td>Edinburgh/online</td><td>£250-400 per appointment</td><td>1-3 months</td></tr><tr><td><strong>London Transgender Clinic</strong></td><td>London</td><td>£200-350 per appointment</td><td>2-4 months</td></tr><tr><td><strong>The Gender Clinic</strong></td><td>Manchester/online</td><td>£300-400 per appointment</td><td>2-4 months</td></tr></tbody></table><h3 id="bridging-prescriptions" tabindex="-1">Bridging Prescriptions <a class="header-anchor" href="#bridging-prescriptions" aria-label="Permalink to &quot;Bridging Prescriptions&quot;">​</a></h3><ul><li>Some GPs will provide bridging prescriptions while waiting for NHS GIC</li><li>This is at the GP&#39;s discretion</li><li>Available through <strong>GenderGP Shared Care</strong> if GP agrees</li></ul><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>Not in EU</strong> — EU prescription cross-border rules do not apply</li><li>Private prescriptions from GenderGP, Gendercare etc. can be dispensed at UK pharmacies</li><li>NHS prescriptions cost £9.90 per item (England)</li><li>Scotland, Wales, NI: Free prescriptions</li><li>HRT medications are generally available at all pharmacies</li></ul><table tabindex="0"><thead><tr><th>Medication</th><th>NHS Cost</th><th>Private Cost</th></tr></thead><tbody><tr><td>Oestradiol (oral/gel/patches)</td><td>£9.90/item</td><td>£10-30/month</td></tr><tr><td>Testosterone (gel/injectable)</td><td>£9.90/item</td><td>£20-50/month</td></tr><tr><td>GnRH agonists (puberty blockers)</td><td>NHS covered</td><td>£80-120/month</td></tr><tr><td>Cyproterone acetate</td><td>£9.90/item</td><td>£15-30/month</td></tr></tbody></table><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li><strong>NHS surgery</strong>: Requires referral from GIC, 2-4 year wait after referral</li><li><strong>Private surgery</strong>: Available through private hospitals</li><li><strong>Chest surgery (top surgery)</strong>: NHS covered, wait 1-3 years; Private £6,000-10,000</li><li><strong>Genital surgery (bottom surgery)</strong>: NHS covered, wait 2-4 years; Private £20,000-40,000</li><li><strong>FFS</strong>: Very limited NHS coverage, private £10,000-40,000</li><li><strong>Voice therapy</strong>: NHS available, wait 1-2 years; private £300-800</li></ul><h2 id="mental-health-support" tabindex="-1">Mental Health Support <a class="header-anchor" href="#mental-health-support" aria-label="Permalink to &quot;Mental Health Support&quot;">​</a></h2><ul><li><strong>GIC psychology teams</strong>: Included in assessment process</li><li><strong>Mind</strong>: LGBTQ+ mental health support</li><li><strong>Switchboard LGBT</strong>: Helpline 0300 330 0630</li><li><strong>Mermaids</strong>: Youth support (under 25)</li><li><strong>Gendered Intelligence</strong>: Counselling and peer support</li><li>London Transgender Clinic: Private counselling £80-150/session</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Status</th></tr></thead><tbody><tr><td>NHS Model</td><td>Gatekeeping</td></tr><tr><td>Average NHS Wait</td><td>2-5 years for first appointment</td></tr><tr><td>Private Options</td><td>Good (GenderGP, Gendercare, etc.)</td></tr><tr><td>Informed Consent</td><td>Available via GenderGP</td></tr><tr><td>Prescription Costs</td><td>£9.90/item (England), free (Scotland/Wales/NI)</td></tr><tr><td>Surgery Coverage</td><td>NHS covers, long waits</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.nhs.uk/conditions/gender-dysphoria/" target="_blank" rel="noreferrer">NHS Gender Identity Services</a></li><li><a href="https://www.gendergp.com/" target="_blank" rel="noreferrer">GenderGP</a></li><li><a href="https://www.gendercare.com/" target="_blank" rel="noreferrer">Gendercare</a></li><li><a href="https://www.thelondontransgenderclinic.uk/" target="_blank" rel="noreferrer">London Transgender Clinic</a></li><li><a href="https://www.transactual.org.uk/" target="_blank" rel="noreferrer">Trans Actual UK - Healthcare Guide</a></li><li><a href="https://mermaidsuk.org.uk/" target="_blank" rel="noreferrer">Mermaids UK</a></li></ul>',28))])}const G=i(h,[["render",c]]);export{f as __pageData,G as default};
